SELECT (SUBSTR(str(?city_inception), 1, 4) AS ?year) WHERE {
  ?event wdt:P31 wd:Q207188;
         wdt:P1545 wd:Q50565992;
         wdt:P585 ?event_date;
         wdt:P2155 ?prize;
         wdt:P276 ?city.
  ?city wdt:P571 ?city_inception.
  FILTER (strstarts(str(?event_date), "2018-"))
  FILTER (isNumeric(?prize))
} ORDER BY DESC(?prize) LIMIT 1

